  `type` enum('assigned_seat','general_admission','standing') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'general_admission',
  `seat_category_ids` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin,
  `allows_seat_selection` tinyint(1) NOT NULL DEFAULT '0',
  `price` decimal(10,2) NOT NULL,
  `capacity` int DEFAULT NULL,
  `available_quantity` int DEFAULT NULL,
  `sold_quantity` int NOT NULL DEFAULT '0',
  `is_active` tinyint(1) NOT NULL DEFAULT '1',
  `display_order` int NOT NULL DEFAULT '0',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `ticket_types_show_id_is_active_index` (`show_id`,`is_active`),
  CONSTRAINT `ticket_types_show_id_foreign` FOREIGN KEY (`show_id`) REFERENCES `shows` (`id`) ON DELETE CASCADE,
  CONSTRAINT `ticket_types_chk_1` CHECK (json_valid(`seat_category_ids`))
) ENGINE=InnoDB AUTO_INCREMENT=8 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
